import React, { useEffect, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import '../../styles/storekeeper/storekeeper-add-product.css';
import api from '../../services/api';

const initialForm = {
  product_code: '',
  product_name: '',
  category_id: '',
  unit: '',
  supplier: '',
  description: '',
  status: 'ACTIVE',
};

const StorekeeperAddProduct = () => {
  const navigate = useNavigate();
  const { productId } = useParams();
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(null);
  const [formData, setFormData] = useState(initialForm);
  const [isEditing, setIsEditing] = useState(false);

  useEffect(() => {
    fetchCategories();
    if (productId) {
      fetchProduct(productId);
    }
  }, [productId]);

  const fetchCategories = async () => {
    try {
      const res = await api.get('/inventory/categories');
      setCategories(res.data?.data || []);
    } catch (err) {
      console.error('Lỗi khi tải danh mục:', err);
      setError('Không thể tải danh mục');
    }
  };

  const fetchProduct = async (id) => {
    try {
      setLoading(true);
      const res = await api.get(`/inventory/products`);
      const product = res.data?.data?.find((p) => String(p.product_id) === String(id));
      
      if (product) {
        setIsEditing(true);
        setFormData({
          product_code: product.product_code || '',
          product_name: product.product_name || '',
          category_id: String(product.category_id || ''),
          unit: product.unit || '',
          supplier: product.supplier || '',
          description: product.description || '',
          status: product.status || 'ACTIVE',
        });
      } else {
        setError('Không tìm thấy sản phẩm');
      }
    } catch (err) {
      console.error('Lỗi khi tải sản phẩm:', err);
      setError('Không thể tải sản phẩm');
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      setLoading(true);
      setError(null);
      setSuccess(null);

      const payload = {
        product_code: formData.product_code.trim(),
        product_name: formData.product_name.trim(),
        category_id: Number(formData.category_id),
        unit: formData.unit.trim(),
        supplier: formData.supplier?.trim() || null,
        description: formData.description?.trim() || null,
        status: formData.status,
      };

      if (isEditing && productId) {
        await api.put(`/inventory/products/${productId}`, payload);
        setSuccess('Cập nhật sản phẩm thành công');
      } else {
        await api.post('/inventory/products', payload);
        setSuccess('Thêm sản phẩm thành công');
        setFormData(initialForm);
      }

      // Redirect to inventory after a short delay
      setTimeout(() => {
        navigate('/storekeeper/inventory');
      }, 1500);
    } catch (err) {
      console.error('Lỗi khi lưu sản phẩm:', err);
      setError(err.response?.data?.message || 'Không thể lưu sản phẩm');
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = () => {
    navigate('/storekeeper/inventory');
  };

  return (
    <div className="storekeeper-add-product dashboard">
      <div className="storekeeper-add-product__header">
        <h1>{isEditing ? '✏️ Cập nhật sản phẩm' : '➕ Thêm sản phẩm mới'}</h1>
        <p>{isEditing ? 'Chỉnh sửa thông tin sản phẩm' : 'Thêm một sản phẩm mới vào kho'}</p>
      </div>

      {error && <div className="storekeeper-add-product__error">{error}</div>}
      {success && <div className="storekeeper-add-product__success">{success}</div>}

      <div className="storekeeper-add-product__container">
        <form className="storekeeper-add-product__form" onSubmit={handleSubmit}>
          <div className="storekeeper-add-product__form-section">
            <h3>Thông tin cơ bản</h3>
            
            <div className="storekeeper-add-product__form-row">
              <div className="storekeeper-add-product__form-group">
                <label htmlFor="product_code">Mã sản phẩm <span className="required">*</span></label>
                <input
                  id="product_code"
                  type="text"
                  name="product_code"
                  placeholder="VD: SP001"
                  value={formData.product_code}
                  onChange={handleChange}
                  disabled={isEditing}
                  required
                  className="storekeeper-add-product__input"
                />
              </div>

              <div className="storekeeper-add-product__form-group">
                <label htmlFor="product_name">Tên sản phẩm <span className="required">*</span></label>
                <input
                  id="product_name"
                  type="text"
                  name="product_name"
                  placeholder="VD: Cá tôm"
                  value={formData.product_name}
                  onChange={handleChange}
                  required
                  className="storekeeper-add-product__input"
                />
              </div>
            </div>

            <div className="storekeeper-add-product__form-row">
              <div className="storekeeper-add-product__form-group">
                <label htmlFor="category_id">Danh mục <span className="required">*</span></label>
                <select
                  id="category_id"
                  name="category_id"
                  value={formData.category_id}
                  onChange={handleChange}
                  required
                  className="storekeeper-add-product__select"
                >
                  <option value="">-- Chọn danh mục --</option>
                  {categories.map((category) => (
                    <option key={category.category_id} value={category.category_id}>
                      {category.category_name}
                    </option>
                  ))}
                </select>
              </div>

              <div className="storekeeper-add-product__form-group">
                <label htmlFor="unit">Đơn vị <span className="required">*</span></label>
                <input
                  id="unit"
                  type="text"
                  name="unit"
                  placeholder="VD: kg, lít, hộp"
                  value={formData.unit}
                  onChange={handleChange}
                  required
                  className="storekeeper-add-product__input"
                />
              </div>
            </div>
          </div>

          <div className="storekeeper-add-product__form-section">
            <h3>Thông tin chi tiết</h3>
            
            <div className="storekeeper-add-product__form-row">
              <div className="storekeeper-add-product__form-group">
                <label htmlFor="supplier">Nhà cung cấp</label>
                <input
                  id="supplier"
                  type="text"
                  name="supplier"
                  placeholder="VD: Công ty ABC"
                  value={formData.supplier}
                  onChange={handleChange}
                  className="storekeeper-add-product__input"
                />
              </div>

              <div className="storekeeper-add-product__form-group">
                <label htmlFor="status">Trạng thái <span className="required">*</span></label>
                <select
                  id="status"
                  name="status"
                  value={formData.status}
                  onChange={handleChange}
                  className="storekeeper-add-product__select"
                >
                  <option value="ACTIVE">Hoạt động</option>
                  <option value="INACTIVE">Không hoạt động</option>
                </select>
              </div>
            </div>

            <div className="storekeeper-add-product__form-group">
              <label htmlFor="description">Mô tả</label>
              <textarea
                id="description"
                name="description"
                placeholder="Nhập mô tả chi tiết sản phẩm..."
                value={formData.description}
                onChange={handleChange}
                rows={4}
                className="storekeeper-add-product__textarea"
              />
            </div>
          </div>

          <div className="storekeeper-add-product__form-actions">
            <button
              type="submit"
              disabled={loading}
              className="storekeeper-add-product__btn storekeeper-add-product__btn--primary"
            >
              {loading ? 'Đang xử lý...' : isEditing ? 'Cập nhật' : 'Thêm mới'}
            </button>
            <button
              type="button"
              onClick={handleCancel}
              disabled={loading}
              className="storekeeper-add-product__btn storekeeper-add-product__btn--secondary"
            >
              Hủy
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default StorekeeperAddProduct;
